                    const step = steps[currentStep];
                    const modalContent = document.getElementById('guideContent');
                    const modalTitle = document.getElementById('guideTitle');
                    const progressBar = document.getElementById('guideProgress');
                    const stepCounter = document.getElementById('stepCounter');
                    const prevBtn = document.getElementById('guidePrevBtn');
                    const nextBtn = document.getElementById('guideNextBtn');
                    
                    if (modalTitle) modalTitle.innerHTML = `<i class="fas ${step.icon} text-${step.color}-500 mr-2"></i>${step.title}`;
