                        { id: 'rw_2', question: '¿Dónde se gestionan los productos y su stock en River-WALL?', options: ['En Facturas', 'En Productos / Inventario', 'En Entregas', 'En Reportes'], correct: 1 },
                        { id: 'rw_3', question: '¿Qué sección permite crear promociones automáticas por productos próximos a caducar?', options: ['Promociones', 'Promociones por Caducidad', 'Configuración', 'POS'], correct: 1 },
                        { id: 'rw_4', question: '¿Dónde se revisan las facturas y ventas realizadas?', options: ['Dashboard', 'Facturas', 'Presupuestos', 'Clientes'], correct: 1 },
                        { id: 'rw_5', question: '¿Qué módulo se utiliza para gestionar proveedores?', options: ['Clientes', 'Proveedores', 'Compras', 'Almacenes'], correct: 1 },
                        { id: 'rw_6', question: '¿Dónde se crean presupuestos para clientes antes de convertirlos en ventas?', options: ['POS', 'Presupuestos', 'Facturas', 'Entregas'], correct: 1 },
                        { id: 'rw_7', question: '¿Cuál es el propósito del módulo Transferencias?', options: ['Vender productos', 'Mover stock entre almacenes', 'Crear facturas', 'Gestionar clientes'], correct: 1 },
                        { id: 'rw_8', question: '¿Dónde se configura la tasa de impuestos y la moneda del negocio?', options: ['POS', 'Configuración', 'Productos', 'Reportes'], correct: 1 },
                        { id: 'rw_9', question: '¿Qué ocurre al convertir un presupuesto a factura en River-WALL?', options: ['Se borra el presupuesto', 'Se crea una venta completada y se descuenta el stock', 'Nada', 'Se envía un email'], correct: 1 },
                        { id: 'rw_10', question: '¿Dónde se pueden ver las alertas de stock bajo y productos agotados?', options: ['Solo en Notificaciones', 'Solo en el Dashboard', 'Dashboard y Notificaciones', 'Solo en Configuración'], correct: 2 }
