            showCashCloseBlockedNotice(syncBlockers = { pending: 0, retrying: 0, conflict: 0, total: 0 }) {
                const details = [];
                if (syncBlockers.pending) details.push(`${syncBlockers.pending} pendientes`);
                if (syncBlockers.retrying) details.push(`${syncBlockers.retrying} en reintento`);
                if (syncBlockers.conflict) details.push(`${syncBlockers.conflict} en conflicto`);

                this.openModal({
                    title: t('modal.cantCloseCash'),
                    content: `
                        <div class="space-y-4">
                            <div class="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl p-4">
                                <p class="text-sm text-amber-700 dark:text-amber-300">${t('cashReg.unresolvedSync')}</p>
                                <p class="text-lg font-bold text-amber-700 dark:text-amber-300">${t('cashReg.blockingClose').replace('{0}', syncBlockers.total)}</p>
                            </div>
                            <p class="text-sm text-slate-600 dark:text-slate-300">${t('cashReg.currentStateLabel')}: ${details.join(' · ') || t('cashReg.noDetail')}.</p>
                            <p class="text-sm text-slate-500 dark:text-slate-400">${t('cashReg.resolveBeforeClose')}</p>
                        </div>
                    `,
                    footer: `
                        <button onclick="ui.closeModal()" class="px-4 py-2 rounded-xl btn-primary-enterprise text-white">${t('cashReg.understood')}</button>
                    `
                });
            }

