            confirmCashMovement() {
                const type = document.getElementById('moveType').value;
                const amount = parseFloat(document.getElementById('moveAmount').value) || 0;
                const concept = document.getElementById('moveConcept').value.trim();
                
                if (amount <= 0) { this.showToast(t('toast.invalidAmountCash'), 'error'); return; }
                if (!concept) { this.showToast(t('toast.enterConcept'), 'error'); return; }
                
                const terminal = store.getActivePosTerminal();
                const terminalId = terminal?.id || 'pos_default';
                const cr = store.getCashRegisterForTerminal(terminalId);
                cr.movements.push({ type, amount, concept, time: Date.now() });
                cr.currentAmount += type === 'in' ? amount : -amount;
                store.data.cashRegisters[terminalId] = cr;
                store.save('cashRegisters');
                // Mantener compatibilidad legacy
                store.data.cashRegister = cr;
                store.save('cashRegister');
                
                this.closeModal();
                this.showToast(t('toast.movementRegistered'), 'success');
                this.navigateTo('cash-register');
            }

